import React, { useState } from 'react';
import Card from '../../components/common/Card';
import Badge from '../../components/common/Badge';
import Button from '../../components/common/Button';
import Spinner from '../../components/common/Spinner';
import Alert from '../../components/common/Alert';
import { useAttendance, useAttendanceHistory } from '../../hooks/useAttendance';
import { formatDate, formatTime, formatHours } from '../../utils/formatters';
import { ATTENDANCE_STATUS } from '../../constants';
import './AttendancePage.css';

const AttendancePage = () => {
  const [page, setPage] = useState(1);
  const { todayAttendance, loading, checkIn, checkOut, actionLoading } = useAttendance();
  const { attendances, pagination, loading: histLoading, refresh } = useAttendanceHistory({ page, limit: 15 });
  const [feedback, setFeedback] = useState(null);

  const handle = async (fn) => {
    const res = await fn();
    setFeedback(res.success ? { type: 'success', msg: res.success ? '✓ Operațiune reușită!' : res.message } : { type: 'danger', msg: res.message });
    refresh();
    setTimeout(() => setFeedback(null), 3500);
  };

  const isCheckedIn  = !!todayAttendance?.checkIn;
  const isCheckedOut = !!todayAttendance?.checkOut;

  if (loading) return <Spinner size="lg" />;

  return (
    <div className="attendance-page">
      {feedback && <Alert type={feedback.type} message={feedback.msg} onClose={() => setFeedback(null)} />}

      {/* Today's card */}
      <Card className="attendance-today">
        <Card.Header>Pontaj Astăzi – {new Date().toLocaleDateString('ro-RO', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}</Card.Header>
        <Card.Body>
          <div className="attendance-today-grid">
            <div className="attendance-time-block">
              <p className="attendance-time-label">Intrare</p>
              <p className="attendance-time-value">{isCheckedIn ? formatTime(todayAttendance.checkIn) : '--:--'}</p>
            </div>
            <div className="attendance-divider">→</div>
            <div className="attendance-time-block">
              <p className="attendance-time-label">Ieșire</p>
              <p className="attendance-time-value">{isCheckedOut ? formatTime(todayAttendance.checkOut) : '--:--'}</p>
            </div>
            <div className="attendance-divider">⏱</div>
            <div className="attendance-time-block">
              <p className="attendance-time-label">Ore lucrate</p>
              <p className="attendance-time-value">{isCheckedOut ? formatHours(todayAttendance.totalHours) : '--'}</p>
            </div>
          </div>

          <div className="attendance-actions">
            {!isCheckedIn && (
              <Button variant="success" size="lg" loading={actionLoading} onClick={() => handle(checkIn)}>
                ▶ Check-In
              </Button>
            )}
            {isCheckedIn && !isCheckedOut && (
              <Button variant="danger" size="lg" loading={actionLoading} onClick={() => handle(checkOut)}>
                ⏹ Check-Out
              </Button>
            )}
            {isCheckedOut && (
              <Badge color="success" size="md">✓ Ziua de lucru completă</Badge>
            )}
          </div>
        </Card.Body>
      </Card>

      {/* History */}
      <Card padding={false}>
        <Card.Header>Istoric Pontaj</Card.Header>
        {histLoading ? <div className="p-4"><Spinner /></div> : (
          <>
            <div className="attendance-table-wrap">
              <table className="attendance-table">
                <thead>
                  <tr>
                    <th>Data</th><th>Intrare</th><th>Ieșire</th><th>Ore</th><th>Ore suplimentare</th><th>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {attendances.length === 0 ? (
                    <tr><td colSpan={6} className="table-empty">Niciun pontaj înregistrat</td></tr>
                  ) : attendances.map((a) => {
                    const st = ATTENDANCE_STATUS[a.status];
                    return (
                      <tr key={a.id}>
                        <td>{formatDate(a.date)}</td>
                        <td>{formatTime(a.checkIn)}</td>
                        <td>{formatTime(a.checkOut)}</td>
                        <td>{formatHours(a.totalHours)}</td>
                        <td>{formatHours(a.overtimeHours)}</td>
                        <td><Badge color={st?.color}>{st?.label}</Badge></td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
            {pagination.totalPages > 1 && (
              <div className="pagination">
                <Button variant="ghost" size="sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>← Precedent</Button>
                <span className="pagination-info">Pagina {page} din {pagination.totalPages}</span>
                <Button variant="ghost" size="sm" disabled={page >= pagination.totalPages} onClick={() => setPage(p => p + 1)}>Următor →</Button>
              </div>
            )}
          </>
        )}
      </Card>
    </div>
  );
};

export default AttendancePage;
